package com.weekend.architect.unift.remote.service.impl;import com.weekend.architect.unift.remote.dto.SavedHostRequest;import com.weekend.architect.unift.remote.enums.ProtocolType;import com.weekend.architect.unift.remote.exception.CredentialValidationException;import com.weekend.architect.unift.remote.service.CredentialValidator;import org.springframework.stereotype.Component;/** * Validates SSH-specific credential fields in a {@link SavedHostRequest}. * * <p>Enforces that the correct credential fields ({@code password}, {@code privateKey}, * {@code passphrase}) are present for the given {@code authType}.  Any protocol other * than {@link ProtocolType#SSH_SFTP} is not handled by this validator. */@Componentpublic class SshCredentialValidator implements CredentialValidator {    @Override    public boolean supports(ProtocolType protocol) {        return protocol == ProtocolType.SSH_SFTP;    }    /**     * Validates SSH credential fields.     *     * <p>The {@code if} statements inside each switch arm are intentional: Java's {@code when}     * guard syntax only applies to type-pattern cases, not to enum-constant case labels.     * Sonar rule S6880 is a false positive for enum switches — suppressed below.     */    @Override    @SuppressWarnings("java:S6880")    public void validate(SavedHostRequest request) {        if (request.getAuthType() == null) {            throw new CredentialValidationException("authType is required for SSH_SFTP protocol");        }        switch (request.getAuthType()) {            case PASSWORD -> {                if (request.getPassword() == null || request.getPassword().isBlank()) {                    throw new CredentialValidationException(                            "password is required when authType=PASSWORD");                }            }            case PRIVATE_KEY -> {                if (request.getPrivateKey() == null || request.getPrivateKey().isBlank()) {                    throw new CredentialValidationException(                            "privateKey is required when authType=PRIVATE_KEY");                }            }            case PRIVATE_KEY_PASSPHRASE -> {                if (request.getPrivateKey() == null || request.getPrivateKey().isBlank()) {                    throw new CredentialValidationException(                            "privateKey is required when authType=PRIVATE_KEY_PASSPHRASE");                }                if (request.getPassphrase() == null || request.getPassphrase().isBlank()) {                    throw new CredentialValidationException(                            "passphrase is required when authType=PRIVATE_KEY_PASSPHRASE");                }            }        }    }}